changeSet.sql:
CREATE TABLE IF NOT EXISTS config.system_modes_current (
    id BIGSERIAL NOT NULL,
    system_mode_current bigint PRIMARY KEY REFERENCES config.system_modes );

CREATE UNIQUE INDEX system_modes_current_singleton ON config.system_modes_current ((true));

INSERT INTO config.system_modes_current(system_mode_current)
SELECT config.system_modes.id
FROM config.system_modes
where system_mode='NORMAL';
